/* Return the largest sum of any contiguous subarray in the vector x.
   This implementation uses Kadane's algorithm (O(n)) and preserves the
   exact semantics of the original quadratic implementation, including
   the behaviour for an empty input vector. */
int maximumSubarray(std::vector<int> const& x) {
    if (x.empty())
        return std::numeric_limits<int>::lowest();  // same as original

    int max_so_far = std::numeric_limits<int>::lowest();
    int max_ending_here = 0;

    for (int val : x) {
        max_ending_here += val;
        if (max_ending_here > max_so_far)
            max_so_far = max_ending_here;
        if (max_ending_here < 0)
            max_ending_here = 0;
    }

    return max_so_far;
}
