#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
//  Optimised single‑thread or multi‑thread DFT
// -----------------------------------------------------------------------------
void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output) {
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Parallelise over the output index k
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);
        const double twopi_over_N = 2.0 * M_PI / static_cast<double>(N);

        for (int n = 0; n < N; ++n) {
            const double angle = twopi_over_N * static_cast<double>(n) * static_cast<double>(k);
            const double c_re = std::cos(angle);
            const double c_im = -std::sin(angle);  // Euler's formula
            sum += std::complex<double>(x[n] * c_re, x[n] * c_im);
        }
        output[k] = sum;
    }
}
