   The result is stored in `bins`.  The implementation uses a parallel reduction
   to minimise cache contention while preserving exact semantics.
*/
void firstLetterCounts(std::vector<std::string> const& s,
                       std::array<size_t, 26> &bins) {
    // Initialise all bins to zero
    bins.fill(0);

    // Thread‑local counts to avoid atomic operations
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<size_t, 26>> local(nthreads);
    for (auto &a : local) a.fill(0);

    #pragma omp parallel
    {
        int id = omp_get_thread_num();
        std::array<size_t, 26> &tbin = local[id];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < s.size(); ++i) {
            const unsigned char c = static_cast<unsigned char>(s[i][0]);
            const int index = c - 'a';
            tbin[index] += 1ULL;
