int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Visit flag – char is smaller and faster than bool.
    std::vector<char> visited(N, 0);
    // Queue implemented with a vector and a head index to avoid the
    // internal overhead of std::queue.
    std::vector<int> q;
    q.reserve(N);
    size_t head = 0;

    visited[source] = 1;
    q.push_back(source);

    // Distance array: 0 for source, increment by 1 per level.
    std::vector<int> dist(N, -1);
    dist[source] = 0;

    while (head < q.size()) {
        int cur = q[head++];

        if (cur == dest) {
            return dist[cur];
        }

        const int base = static_cast<int>(cur) * static_cast<int>(N);
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (A[base + i] && !visited[i]) {
                visited[i] = 1;
                dist[i] = dist[cur] + 1;
                q.push_back(i);
            }
        }
    }

    return std::numeric_limits<int>::max();   // unreachable – should not happen for connected graphs
}
