    and preserves the exact semantics of the original sequential
    implementation.
*/
void countQuadrants(std::vector<Point> const& points, std::array<std::size_t, 4>& bins) {
    // Initialize result bins
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Each thread keeps a private accumulator to avoid race conditions.
    // Reduction is performed at the end of the parallel loop.
