    for (std::size_t i = 0; i < points.size(); ++i) {
        const Point& p = points[i];
        std::size_t local0 = 0, local1 = 0, local2 = 0, local3 = 0;

        if (p.x >= 0.0) {
            if (p.y >= 0.0)
                ++local0;          // First quadrant
            else
                ++local3;          // Fourth quadrant
        } else {
            if (p.y >= 0.0)
                ++local1;          // Second quadrant
            else
                ++local2;          // Third quadrant
        }

#pragma omp atomic
        bins[0] += local0;
#pragma omp atomic
        bins[1] += local1;
#pragma omp atomic
        bins[2] += local2;
#pragma omp atomic
        bins[3] += local3;
