```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>
#include <immintrin.h>

/*
 * Compute the ReLU function on every element of x. Elements less than zero become zero,
 * while elements greater than zero stay the same.
 *
 * The implementation is optimized for modern x86-64 processors, using OpenMP for parallel
 * execution and SIMD intrinsics for vectorised computation. Batch size is aligned to 4 (AVX size)
 * to minimise memory traffic and to keep the loop vectorised.
 */
inline void relu(std::vector<double> &x) {
    const std::size_t n = x.size();

    // Process in chunks of 4 doubles (32 bytes) with AVX
    const std::size_t chunk = 4;
    const std::size_t aligned_end = n - (n % chunk);

    // Parallel for with static scheduling – the cost of each iteration is the same.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < aligned_end; i += chunk) {
        // Load 4 doubles
        __m256d v = _mm256_loadu_pd(&x[i]);

        // Broadcast 0.0 to all lanes
        __m256d zero = _mm256_setzero_pd();

        // max(v, 0.0) per element
        __m256d r = _mm256_max_pd(v, zero);

        // Store back
        _mm256_storeu_pd(&x[i], r);
    }

    // Handle the tail elements that don't fit into a 256-bit vector
    for (std::size_t i = aligned_end; i < n; ++i) {
        x[i] = (x[i] > 0.0) ? x[i] : 0.0;
    }
}
