inline void pixelCounts(const std::vector<int> &image,
                        std::array<std::size_t, 256> &bins)
{
    constexpr std::size_t BINS = 256;

    /* Zero out the destination array */
    std::fill(bins.begin(), bins.end(), 0);

    /* Parallel work: each thread builds its own sparse
       histogram into a thread‑local array.  The array is allocated
       in the private clause to avoid false sharing. */
    #pragma omp parallel
    {
        std::array<std::size_t, BINS> local{};
        std::fill(local.begin(), local.end(), 0);

        /* Distribute the workload statically to keep the
           work balanced and avoid dynamic scheduling overhead. */
        #pragma omp for schedule(static)
        for (std::size_t idx = 0; idx < image.size(); ++idx) {
            /* `image[idx]` is guaranteed to be in 0..255 by contract. */
            ++local[static_cast<std::size_t>(image[idx])];
        }

        /* Merge local histogram into the global one at the
           end of the parallel region to guarantee thread safety. */
        #pragma omp critical
        {
            for (std::size_t i = 0; i < BINS; ++i)
                bins[i] += local[i];
