#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

// -----------------------------------------------------------------
// Optimised sparse matrix–matrix multiplication
// Y = A * X   (A: MxK COO, X: KxN COO, Y: MxN dense)
// -----------------------------------------------------------------
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
   // Initialise the dense result to zero
   Y.assign(M * N, 0.0);

   // Build a hash map from X.row → list of (column, value) pairs
   // This replaces the inner scan over all X elements
   std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> xbyrow;
   xbyrow.reserve(X.size()*2);           // a rough over‑estimate
   for (auto const& x : X)
       xbyrow[x.row].emplace_back(x.column, x.value);

   // Parallel over the non‑zeros of A (outer loop)
   #pragma omp parallel for schedule(dynamic, 1024)
   for (size_t ia = 0; ia < A.size(); ++ia) {
       auto const& a = A[ia];
       auto it = xbyrow.find(a.column);
       if (it == xbyrow.end()) continue;           // no matching X rows

       double const valA = a.value;
       size_t const rowA  = a.row;
       size_t const base  = rowA * N;               // starting offset of this row in Y

       // Accumulate contributions for this single A non‑zero
       for (auto const& [colX, valX] : it->second) {
           Y[base + colX] += valA * valX;
       }
   }
}
