```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>

/* Count the number of connected components in the undirected graph
   defined by the adjacency matrix A.  A is an NxN adjacency matrix
   stored in row-major order, 0/1 entries, undirected.
   The function is strict about producing the same result as the
   original reference implementation while trying to run faster on
   modern x86‑64 CPUs (gcc -O2).  */

inline void
dfs_iterative(std::vector<int> const& A, std::size_t start, std::size_t N,
              std::vector<char>& visited)
{
    std::size_t idx = start * N;
    // Simple stack implemented in a vector; reserve maximum possible size
    static thread_local std::vector<std::size_t> stack;
    if (stack.capacity() < N) stack.reserve(N);

    stack.clear();
    stack.push_back(start);
    visited[start] = 1;

    while (!stack.empty()) {
        std::size_t node = stack.back();
        stack.pop_back();

        std::size_t base = node * N;
        for (std::size_t j = 0; j < N; ++j) {
            // Quick path: skip if already visited or no edge
            if (!visited[j] && A[base + j] == 1) {
                visited[j] = 1;
                stack.push_back(j);
            }
        }
    }
}

int componentCount(std::vector<int> const& A, std::size_t N)
{
    // Use a packed byte array for visited (char = 1 byte)
    std::vector<char> visited(N, 0);
    int count = 0;

    for (std::size_t i = 0; i < N; ++i) {
        if (!visited[i]) {
            dfs_iterative(A, i, N, visited);
            ++count;
        }
    }
    return count;
}
