/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
*/
inline void spmv(double alpha,
                 std::vector<COOElement> const& A,
                 std::vector<double> const& x,
                 double beta,
                 std::vector<double> &y,
                 size_t /*M*/, size_t /*N*/) {

    // 1. Scale y by beta
    #pragma omp parallel for
    for (size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    // 2. Prepare per‑thread local buffers for contributions
    int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> local_y(nthreads, std::vector<double>(y.size(), 0.0));

    // 3. Parallel accumulation of COO contributions
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        double *ldy = local_y[tid].data();

        #pragma omp for schedule(static)
        for (size_t k = 0; k < A.size(); ++k) {
            const COOElement &e = A[k];
            // bounds check (same as original)
            if (e.row < y.size() && e.column < x.size()) {
                ldy[e.row] += alpha * e.value * x[e.column];
            }
        }
    }

    // 4. Reduce local buffers into y
    #pragma omp parallel for
    for (size_t i = 0; i < y.size(); ++i) {
        double sum = 0.0;
        for (int t = 0; t < nthreads; ++t) {
            sum += local_y[t][i];
        }
        y[i] += sum;
    }
