// ------------------------------------------------------------
//  Optimised implementation of largestComponent
// ------------------------------------------------------------

// Helper: non‑recursive depth‑first search that writes the size
// of the component being explored into *cnt.  The adjacency matrix
// is stored in flat row-major form (0 = no edge, 1 = edge).
inline void dfs_component(const std::vector<int>& A,
                          size_t N,
                          std::vector<uint8_t>& visited,
                          size_t start,
                          size_t* cnt)
{
    std::stack<size_t> st;
    st.push(start);
    visited[start] = 1;
    size_t localCnt = 0;

    while (!st.empty()) {
        size_t v = st.top();
        st.pop();
        ++localCnt;

        // iterate over the row of v
        // linear scan keeps cache locality
        size_t base = v * N;
        for (size_t u = 0; u < N; ++u) {
            if (A[base + u] && !visited[u]) {
                visited[u] = 1;
                st.push(u);
            }
        }
    }
    *cnt = localCnt;
}

// ------------------------------------------------------------
//  Main function exposed to the harness
// ------------------------------------------------------------
int largestComponent(const std::vector<int>& A, size_t N)
{
    // Use a byte per vertex instead of std::vector<bool>
    std::vector<uint8_t> visited(N, 0);
    size_t globalMax = 0;

    // Single thread is sufficient; searching each component
    // is inherently sequential because vertices get marked visited
    for (size_t i = 0; i < N; ++i) {
        if (!visited[i]) {
            size_t componentSize = 0;
            dfs_component(A, N, visited, i, &componentSize);
            if (componentSize > globalMax) {
                globalMax = componentSize;
            }
        }
    }

    return static_cast<int>(globalMax);
}
