49_sparse_la_sparse_lu_decomp:
```cpp
#pragma once
#include <vector>

struct COOElement {
    size_t row, column;
    double value;
};

/* LU factorization of a sparse NxN matrix A (COO format) into
 * L (lower triangular, unit diagonal) and U (upper triangular).
 *
 * The function preserves the original behaviour while avoiding
 * unnecessary temporary objects and making the inner loops
 * cache‑friendly.
 */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double> &L,
                 std::vector<double> &U,
                 size_t N)
{
    /* Allocate the dense matrix once */
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A)
        fullA[e.row * N + e.column] = e.value;

    /* Ensure L and U have the correct size */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    for (size_t i = 0; i < N; ++i)
    {
        /* Upper part (including the diagonal) */
        for (size_t j = i; j < N; ++j)
        {
            double val = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k)
                val -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = val;
        }

        /* Lower part */
        for (size_t j = 0; j < i; ++j)
        {
            double val = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k)
                val -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = val / U[j * N + j];
        }

        L[i * N + i] = 1.0;          // unit diagonal
    }
}
