/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x)
{
    // The vector needs to have at least two elements
    if (x.size() < 2) {
        return 0.0;
    }

    /* --- 1. Sort a copy of the input ------------------------------------ */
    std::vector<double> a = x;
    std::sort(a.begin(), a.end());          // O(n log n)

    /* --- 2. Scan the sorted array to find the minimal adjacent difference */
    double minDist = std::numeric_limits<double>::max();

    // If we find two equal elements the distance is zero - early exit
    for (size_t i = 1; i < a.size(); ++i) {
        const double d = a[i] - a[i - 1];   // non‑negative because a is sorted
        if (d == 0.0) {
            return 0.0;
        }
        if (d < minDist) {
            minDist = d;
        }
    }

    return minDist;
}
