/*  For each cell find how many orthogonal neighbours are 1
    and set the cell to 1 iff that count is exactly 1.
*/
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N)
{
    // use raw pointers for speed
    const int *in  = input.data();
    int *out = output.data();
    const size_t stride = N;              // row length

    /* OpenMP parallelisation over the 2‑D grid.
       collapsed loops give better load balance on large N.
    */
#pragma omp parallel for collapse(2)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            int count = 0;
            size_t idx = i * stride + j;
            if (i && in[idx - stride] == 1) ++count;    // north
            if (i + 1 < N && in[idx + stride] == 1) ++count; // south
            if (j && in[idx - 1] == 1) ++count;        // west
            if (j + 1 < N && in[idx + 1] == 1) ++count; // east
            out[idx] = (count == 1) ? 1 : 0;
        }
    }
}
