#pragma once
#include <cmath>
#include <vector>
#include <complex>
#include <algorithm>
#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

// |N| must be a power of two
inline void fft_inplace(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // ----- Bit‑reverse permutation -----
    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i)
    {
        if (i < rev)
            std::swap(x[i], x[rev]);

        std::size_t mask = N;
        for (;;)
        {
            mask >>= 1;
            if ((rev & mask) == 0)
            {
                rev |= mask;
                break;
            }
            rev &= ~mask;
        }
    }

    // ----- Cooley‑Tukey FFT -----
    for (std::size_t len = 2; len <= N; len <<= 1)
    {
        const double theta = -2 * M_PI / len;
        const std::complex<double> wlen(std::cos(theta), std::sin(theta));

        for (std::size_t i = 0; i < N; i += len)
        {
            std::complex<double> w(1.0, 0.0);
#pragma omp simd
            for (std::size_t j = 0; j < len/2; ++j)
            {
                const std::complex<double> u = x[i + j];
                const std::complex<double> v = x[i + j + len/2] * w;
                x[i + j]           = u + v;
                x[i + j + len/2]   = u - v;

                w *= wlen;
            }
        }
    }
}

inline void ifft_inplace(std::vector<std::complex<double>>& x)
{
    // Conjugate, forward FFT, conjugate again, scale
    std::transform(x.begin(), x.end(), x.begin(), [](const std::complex<double>& a){ return std::conj(a); });
    fft_inplace(x);
    std::transform(x.begin(), x.end(), x.begin(), [](const std::complex<double>& a){ return std::conj(a); });
    const double invN = 1.0 / static_cast<double>(x.size());
    std::transform(x.begin(), x.end(), x.begin(), [invN](const std::complex<double>& a){ return a * invN; });
}
