/* Compute one iteration of a 3‑point 1D Jacobi stencil on `input`.
   Each element of `input` will be averaged with its two neighbors and stored in
   the corresponding element of `output`.  Boundary values are treated as zero.
   This implementation is highly optimised for modern x86‑64 CPUs: it
   - eliminates branches in the inner loop,
   - uses pointer arithmetic for minimal indirection,
   - splits the first and last element as separate trivial cases,
   - and distributes work with OpenMP to use all available cores.
   The function signature is unchanged, so it can be dropped in place of the
   original code without affecting the harness.  */
inline void jacobi1D(std::vector<double> const &input,
                     std::vector<double> &output) noexcept
{
    const std::size_t N = input.size();
    if (N == 0) return;

    // Handle first and last elements (no neighbors on one side)
    output[0]     = input[0] / 3.0;
    output[N - 1] = input[N - 1] / 3.0;

    // Main loop – the bulk of the work is performed here
    // We avoid bounds checks inside the loop by starting at 1
    // and running to N-2.
    const double *in  = input.data();
    double       *out = output.data();

    #pragma omp parallel for schedule(static)
    for (long long i = 1; i < static_cast<long long>(N - 1); ++i) {
        // Load neighbouring values
        const double left  = in[i - 1];
        const double mid   = in[i];
        const double right = in[i + 1];

        // Compute the average
        out[i] = (left + mid + right) / 3.0;
    }
}
