#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <omp.h>

/*
 * Replace the i‑th element of the vector x with the minimum value from indices
 * 0 through i.
 *
 * This implementation performs the calculation in two passes using OpenMP:
 *   1. Each thread computes the local minimum of its chunk.
 *   2. The thread‑local minima are reduced into a prefix array and used to
 *      fill each element of x in parallel.
 *
 * The algorithm preserves the exact behaviour of the reference implementation
 * and achieves good parallel speedups on systems with multiple cores.
 */
inline void partialMinimums( std::vector<float> &x )
{
    const std::size_t n = x.size();
    if (n == 0) return;

    const int      threads = omp_get_max_threads();
    const std::size_t chunk  = (n + threads - 1) / threads;

    std::vector<float> chunk_min( threads, std::numeric_limits<float>::max() );

    /* 1. Compute the minimum for each chunk. */
    #pragma omp parallel for schedule(static, chunk)
    for ( std::size_t i = 0; i < n; ++i ) {
        const int  t = static_cast<int>(i / chunk);
        const float val = x[i];
        if (val < chunk_min[t]) chunk_min[t] = val;
    }

    /* 2. Prefix‑reduce the chunk minima to obtain the global minimum up to each chunk. */
    std::vector<float> prefix_min( threads );
    float acc = std::numeric_limits<float>::max();
    for (int t = 0; t < threads; ++t) {
        acc = std::min( acc, chunk_min[t] );
        prefix_min[t] = acc;
    }

    /* 3. Re‑run through each chunk, maintaining a running minimum that starts
     *    with the appropriate prefix value from the previous chunks. */
    #pragma omp parallel for schedule(static, chunk)
    for ( std::size_t i = 0; i < n; ++i ) {
        const int  t = static_cast<int>(i / chunk);
        float &val = x[i];
        if (i == 0) {
            // first element stays unchanged
            continue;
        }
        const float prev_min = (t == 0) ? std::numeric_limits<float>::max()
                                        : prefix_min[t-1];
        const float running_min = (i % chunk == 0)
                                  ? std::min(prev_min, val)
                                  : std::min(x[i-1], val);
        val = running_min;
    }
}
