struct Point {
    double x, y;
};

/* Helper to compute the absolute area of a triangle formed by three points */
inline double triArea(const Point& a, const Point& b, const Point& c) noexcept {
    return 0.5 * std::abs(a.x * (b.y - c.y) +
                         b.x * (c.y - a.y) +
                         c.x * (a.y - b.y));
}

/* Return the area of the smallest triangle that can be formed by any 3 points.
   The implementation is fully deterministic and preserves the original
   semantics while being optimised for speed.
*/
inline double smallestArea(std::vector<Point> const& points) noexcept {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;                      // No triangle possible

    double global_min = std::numeric_limits<double>::max();

    /* Parallelise the outermost loop with an OpenMP reduction on the
       minimum area.  The work‐sharing is split across the available
       threads (8 on the target platform).  No false sharing occurs
       because each thread works on disjoint slices of the data. */
#pragma omp parallel for schedule(dynamic) reduction(min:global_min)
    for (std::size_t i = 0; i < n - 2; ++i) {
        const Point& pi = points[i];
        double thread_min = global_min;         // Local copy for this thread

        for (std::size_t j = i + 1; j < n - 1; ++j) {
            const Point& pj = points[j];
            for (std::size_t k = j + 1; k < n; ++k) {
                const double area = triArea(pi, pj, points[k]);
                if (area < thread_min) {
                    thread_min = area;
                }
            }
        }
        /* Update the global minimum.  The reduction clause guarantees
           that this assignment is thread‑safe. */
        if (thread_min < global_min) global_min = thread_min;
    }

    return global_min;
}
