```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/// LU factorization (in-place, Doolittle) with OpenMP acceleration.
/// The matrix is stored in row-major order and modified in place.
/// No pivoting is used – the algorithm fails for singular or zero pivots,
/// which matches the behaviour of the original reference implementation.
inline void luFactorize(std::vector<double> &A, size_t N) {
    double * const restrict mat = A.data();          // raw pointer for speed
    const size_t Ncol = N;                          // use a local alias for the inner loop bound

    /* Work level: each iteration of the outer k-loop is independent once the
       updates of rows k+1..N-1 have finished.  We parallelise over those rows.
       The inner update of each row is deliberately kept sequential because
       it is memory bound and the overhead of nested parallelism would
       outweigh the benefit.  */
    for (size_t k = 0; k < N; ++k) {
        const double * restrict pivotRow = mat + k * Ncol;         // A[k][*]
        const double pivot = pivotRow[k];                         // A[k][k]

        /* Parallel over the rows below the current pivot row. */
        #pragma omp parallel for schedule(static)
        for (size_t i = k + 1; i < N; ++i) {
            double * restrict curRow = mat + i * Ncol;             // A[i][*]
            double factor = curRow[k] / pivot;                    // L[i][k]
            curRow[k] = factor;                                   // store L[i][k]

            /* Update the remaining entries in the row.
               The subtraction lives in the cache after the first access. */
            for (size_t j = k + 1; j < Ncol; ++j) {
                curRow[j] -= factor * pivotRow[j];
            }
        }
    }
