struct Point {
    double x, y;
};

// Return the distance between the closest two points in the vector points.
inline double closestPair(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 2) return 0.0;

    // Helper to compute squared distance
    auto dist2 = [](const Point& a, const Point& b) {
        double dx = a.x - b.x;
        double dy = a.y - b.y;
        return dx * dx + dy * dy;
    };

    // Pre‑sort points by x (and y to break ties)
    std::vector<Point> px(points);
    std::sort(px.begin(), px.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Recursive function: works on a range [l, r) in px
    std::function<double(int, int)> closestRec = [&](int l, int r) -> double {
        int sz = r - l;
        if (sz <= 3) {  // Brute‑force for small sets
            double best = std::numeric_limits<double>::infinity();
            for (int i = l; i < r; ++i)
                for (int j = i + 1; j < r; ++j)
                    best = std::min(best, dist2(px[i], px[j]));
            return sqrt(best);
        }

        int m = l + sz / 2;
        double midx = px[m].x;

        double dLeft  = closestRec(l, m);
        double dRight = closestRec(m, r);
        double d = std::min(dLeft, dRight);
        double d2 = d * d;

        // Build strip of points within d of the median line
        std::vector<Point> strip;
        strip.reserve(sz);
        for (int i = l; i < r; ++i) {
            if ((px[i].x - midx) * (px[i].x - midx) < d2)
                strip.push_back(px[i]);
        }

        // Sort strip by y-coordinate
        std::sort(strip.begin(), strip.end(),
                  [](const Point& a, const Point& b){ return a.y < b.y; });

        // Check up to 7 neighbors in the strip
        for (size_t i = 0; i < strip.size(); ++i) {
            for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) * (strip[j].y - strip[i].y) < d2; ++j) {
                double d2ij = dist2(strip[i], strip[j]);
                if (d2ij < d2) {
                    d2 = d2ij;
                    d = sqrt(d2);
                }
            }
        }
        return d;
    };

    return closestRec(0, n);
}
