#pragma once
#include <vector>
#include <algorithm>

struct Point
{
    double x, y;
};

/* Return the vertices of the convex hull of `points` in counter‑clockwise
 * order. The result is written into `hull`. The algorithm is an
 * O(n log n) implementation of Andrew's monotone chain. */
inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline bool cmpPoints(const Point& a, const Point& b) noexcept
{
    return a.x < b.x || (a.x == b.x && a.y < b.y);
}

inline void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const std::size_t n = points.size();
    if (n < 3)
    {
        hull = points;
        return;
    }

    // Sort a copy of the points
    std::vector<Point> sorted = points;
    std::sort(sorted.begin(), sorted.end(), cmpPoints);

    // Upper bound for hull size: at most 2n
    std::vector<Point> buf;
    buf.reserve(2 * n);

    // Build lower hull
    for (const auto& p : sorted)
    {
        while (buf.size() >= 2 &&
               cross(buf[buf.size() - 2], buf[buf.size() - 1], p) <= 0)
            buf.pop_back();
        buf.push_back(p);
    }

    // Build upper hull
    const std::size_t lowerSize = buf.size();
    for (std::size_t i = n - 1; i > 0; --i)
    {
        const Point& p = sorted[i - 1];
        while (buf.size() > lowerSize &&
               cross(buf[buf.size() - 2], buf[buf.size() - 1], p) <= 0)
            buf.pop_back();
        buf.push_back(p);
    }

    // Last point is omitted because it is the same as the first point
    buf.pop_back();

    hull = std::move(buf);
}
