inline constexpr size_t BLOCK_SIZE = 64;   // tile size that fits into L1 cache

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row-major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]
*/
void gemm(const std::vector<double>& A,
          const std::vector<double>& B,
          std::vector<double>& C,
          const size_t M,
          const size_t K,
          const size_t N) {
    // Assume C is pre‑initialised to zero or that we need to accumulate.
    const size_t bs = BLOCK_SIZE;

    // Parallelise over outer dimension blocks of rows.
    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += bs) {
        const size_t i_end = std::min(i0 + bs, M);
        for (size_t k0 = 0; k0 < K; k0 += bs) {
            const size_t k_end = std::min(k0 + bs, K);
            for (size_t j0 = 0; j0 < N; j0 += bs) {
                const size_t j_end = std::min(j0 + bs, N);

                // --- inner triple loop inside the current tile ---
                for (size_t i = i0; i < i_end; ++i) {
                    const double* Ai = &A[i * K];
                    double* Ci = &C[i * N];
                    for (size_t k = k0; k < k_end; ++k) {
                        const double aik = Ai[k];
                        const double* Bk = &B[k * N];
                        for (size_t j = j0; j < j_end; ++j) {
                            Ci[j] += aik * Bk[j];
                        }
                    }
                }
            }
        }
    }
}
```
This tiled implementation exploits spatial locality, reducing cache misses, and the outer `#pragma omp parallel for` distributes independent row blocks among the 8 hardware threads. The algorithm preserves the exact mathematical result while significantly improving performance on modern x86‑64 hardware.

