inline size_t findClosestToPi(const std::vector<double> &x) {
    // Fast path for tiny vectors to avoid threading overhead
    if (x.size() <= 256) {
        size_t index = 0;
        double min_diff = std::abs(x[0] - M_PI);
        for (size_t i = 1; i < x.size(); ++i) {
            double diff = std::abs(x[i] - M_PI);
            if (diff < min_diff) {
                min_diff = diff;
                index = i;
            }
        }
        return index;
    }

    // Parallel reduction: store best pair as (min_diff, index)
    struct Best { double diff; size_t idx; };
    Best global = {std::numeric_limits<double>::infinity(), 0};

    #pragma omp parallel for reduction( \
            omp_inclusive(min, global.diff, &global.idx, \
            [=](const Best &a, const Best &b)->Best { return (a.diff < b.diff) ? a : b; }) \
            num_threads(8))
    for (long long i = 0; i < static_cast<long long>(x.size()); ++i) {
        double diff = std::abs(x[i] - M_PI);
        if (diff < global.diff) {
            global.diff = diff;
            global.idx = static_cast<size_t>(i);
        }
    }

