// Sorts the vector in place, keeping all zeros in their original locations.
// Non‑zero values are sorted in ascending order.
// The implementation uses a parallel sort to take advantage of the
// 8 hardware threads available on the target platform.
inline void sortIgnoreZero(std::vector<int> &x)
{
    // Count non‑zero elements first: this allows us to reserve the exact
    // needed capacity without a second pass.
    size_t nonZeroCount = 0;
    for (const int v : x) {
        if (v != 0) ++nonZeroCount;
    }

    // Extract all non‑zero elements.  Reserve once to avoid reallocations.
    std::vector<int> nonZero;
    nonZero.reserve(nonZeroCount);
    for (const int v : x) {
        if (v != 0) nonZero.push_back(v);
    }

    // Sort the extracted slice in parallel.
    // __gnu_parallel::sort is an implementation of parallel quick‑sort /
    // introsort that maps to the OpenMP runtime (since we compiled with
    // -fopenmp, its internal parallelism uses the available thread pool).
    __gnu_parallel::sort(nonZero.begin(), nonZero.end());

    // Re‑insert the sorted values, preserving zero locations.
    size_t idx = 0;
    for (int &v : x) {
        if (v != 0) v = nonZero[idx++];
    }
