struct Result {
    int startTime;
    int duration;
    float value;
};

/// Parallel quick‑sort implementation with OpenMP.
/// Only sorts the vector by `startTime` – the behaviour matches the
/// original serial version but can take advantage of multiple threads.
inline void parallelQuickSort(std::vector<Result>::iterator first,
                              std::vector<Result>::iterator last) {
    // Threshold for using insertion sort on small ranges.
    constexpr std::size_t cutOff = 32;
    if (last - first <= cutOff) {
        std::inplace_merge(first, first + (last - first) / 2, last,
                           [](const Result& a, const Result& b) {
                               return a.startTime < b.startTime;
                           });
        return;
    }

    // Choose pivot (median of three).
    auto mid = first + (last - first) / 2;
    std::nth_element(first, mid, last,
                      [](const Result& a, const Result& b) {
                          return a.startTime < b.startTime;
                      });

    // Partition around the pivot.
    std::partition_point(first, last,
                         [pivot = *mid](const Result& r) {
                             return r.startTime < pivot.startTime;
                         });

    // Recursively sort the two partitions in parallel.
    #pragma omp task shared(first, mid) default(none)
    {
        parallelQuickSort(first, mid);
    }
    #pragma omp task shared(mid, last) default(none)
    {
        parallelQuickSort(mid, last);
    }
}

/// Public API – keeps the original function signature.
inline void sortByStartTime(std::vector<Result>& results) {
    if (results.empty())
        return;

    // Single parallel region with a single task that spawns subtasks.
    #pragma omp parallel
    {
        #pragma omp single nowait
        {
            parallelQuickSort(results.begin(), results.end());
        }
    }
}
