/* Return the perimeter of the convex hull of the given points. */
double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Make a copy and sort by x, then y.
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& p1, const Point& p2) {
                  return (p1.x < p2.x) || (p1.x == p2.x && p1.y < p2.y);
              });

    std::vector<Point> hull;
    hull.reserve(2 * n);

    // Build lower hull
    for (const auto& p : sorted) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // Build upper hull
    const std::size_t lowerSize = hull.size();
    for (auto it = sorted.rbegin(); it + 1 != sorted.rend(); ++it) {
        const Point& p = *it;
        while (hull.size() > lowerSize &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // Remove the duplicated first point
    hull.pop_back();

    // Parallel perimeter calculation.
    double perimeter = 0.0;
#pragma omp parallel for reduction(+:perimeter) schedule(static)
    for (std::size_t i = 0; i < hull.size(); ++i) {
        std::size_t j = (i + 1) % hull.size();
        perimeter += dist(hull[i], hull[j]);
    }
    return perimeter;
