/* Simulate one generation of Conway's Game of Life.
 *
 * `input`  : current state, row‑major NxN grid, values 0/1.
 * `output` : resulting state, same format as `input`.
 * `N`      : size of the grid (NxN).
 *
 * Behavior matches the reference implementation exactly.
 * The function is fully parallelised with OpenMP and optimises
 * cache locality by using row‑major traversal and by avoiding
 * runtime branching where possible.
 */
inline void gameOfLife(std::vector<int> const &input,
                       std::vector<int> &output,
                       size_t N)
{
    // Ensure output is the correct size – this check keeps old behavior.
    if (output.size() != N * N) output.resize(N * N);

    const int *in  = input.data();
    int       *out = output.data();

    // Parallelize the outer loop.  The inner loop is cache‑friendly
    // because we iterate row by row.  `collapse(2)` allows the work
    // to be distributed evenly among threads; `schedule(static)`
    // gives the best performance on typical x86‑64 CPUs.
#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t row_idx  = i * N;
        const size_t row_above_idx = (i > 0) ? (i - 1) * N : 0;
        const size_t row_below_idx = (i + 1 < N) ? (i + 1) * N : 0;

        for (size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            // Vertical neighbours
            if (i > 0)       sum += in[row_above_idx + j];
            if (i + 1 < N)   sum += in[row_below_idx + j];

            // Horizontal neighbours
            if (j > 0)       sum += in[row_idx + j - 1];
            if (j + 1 < N)   sum += in[row_idx + j + 1];

            // Diagonal neighbours
            if (i > 0 && j > 0)               sum += in[row_above_idx + j - 1];
            if (i > 0 && j + 1 < N)           sum += in[row_above_idx + j + 1];
            if (i + 1 < N && j > 0)           sum += in[row_below_idx + j - 1];
            if (i + 1 < N && j + 1 < N)       sum += in[row_below_idx + j + 1];

            // Apply the Game of Life rules without branching
            const int cur = in[row_idx + j];
            const int alive = cur * ( (sum == 2) | (sum == 3) ) + ((sum == 3) & !cur);
            out[row_idx + j] = alive;
        }
    }
}
