struct Element {
    std::size_t index;
    double      value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
   x and y are assumed to be sorted in increasing index order and
   contain at most one entry per index.  The result is accumulated
   into the dense vector z, which must already be sized appropriately.
*/
inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double>        &z)
{
    std::size_t xi = 0, yi = 0;
    const std::size_t xn = x.size(), yn = y.size();

    /* Merge the two input vectors.  We keep this part sequential
       because the work is intrinsically ordered by the indices. */
    while (xi < xn && yi < yn) {
        const std::size_t i_x = x[xi].index;
        const std::size_t i_y = y[yi].index;

        if (i_x < i_y) {
            z[i_x] += alpha * x[xi].value;
            ++xi;
        } else if (i_x > i_y) {
            z[i_y] += y[yi].value;
            ++yi;
        } else { /* i_x == i_y */
            z[i_x] += alpha * x[xi].value + y[yi].value;
            ++xi;
            ++yi;
        }
    }

    /* Process the remaining tail of x.  This loop can be parallelised
       safely because indices are unique in each vector. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = xi; i < xn; ++i) {
        z[x[i].index] += alpha * x[i].value;
    }

    /* Process the remaining tail of y.  Same reasoning as above. */
    #pragma omp parallel for schedule(static)
    for (std::size_t j = yi; j < yn; ++j) {
        z[y[j].index] += y[j].value;
    }
}
