    // ---------------------------------------------------------------------
    // Pre‑compute reversed indices for the current size
    const std::size_t numBits = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t revIdx = 0;
        for (std::size_t b = 0; b < numBits; ++b)
            if (i & (1u << b))
                revIdx |= (1u << (numBits - 1 - b));
        rev[i] = revIdx;
    }

    // Parallel in‑place swap
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }

    // ---------------------------------------------------------------------
    // 2. Iterative Cooley–Tukey
    // ---------------------------------------------------------------------
    for (std::size_t s = 1; s <= numBits; ++s) {
        const std::size_t m = 1u << s;         // size of sub‑FFT
        const std::size_t m2 = m >> 1;         // half size
        const double theta = -2.0 * M_PI / static_cast<double>(m);
        const std::complex<double> wm = std::exp(std::complex<double>(0.0, theta));

        // Parallel over the outer loops (blocks)
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < m2; ++j) {
                std::complex<double> t = w * output[k + j + m2];
                std::complex<double> u = output[k + j];
                output[k + j]     = u + t;
                output[k + j + m2] = u - t;
                w *= wm;
            }
        }
    }
}
