/*
 * Very small in‑place radix‑2 FFT for power‑of‑two sizes.
 * The implementation follows the decimation‑in‑time Cooley‑Tukey
 * algorithm used by the reference code, but the body has been
 * reorganised for speed and parallelism while keeping identical
 * numerical results when compiled with -O2.
 *
 * The routine produces the same output as the reference implementation
 * for all inputs that are a power of two in length and where
 * std::log2(N) is integral.
 *
 * Parameters:
 *     x – input complex vector
 *     r – output real part (pre‑allocated to size N)
 *     i – output imaginary part (pre‑allocated to size N)
 */

static inline void bit_reverse_inplace(std::vector<std::complex<double>>& a)
{
    const std::size_t N = a.size();
    const unsigned int m = static_cast<unsigned int>(std::log2(N));

    for (std::size_t i = 0; i < N; ++i)
    {
        // Compute reversed index
        std::size_t j = i;
        j = ((j & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((j & 0x5555555555555555ULL) << 1);
        j = ((j & 0xccccccccccccccccULL) >> 2) | ((j & 0x3333333333333333ULL) << 2);
        j = ((j & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((j & 0x0f0f0f0f0f0f0f0fULL) << 4);
        j = ((j & 0xff00ff00ff00ff00ULL) >> 8) | ((j & 0x00ff00ff00ff00ffULL) << 8);
        j = ((j & 0xffff0000ffff0000ULL) >> 16) | ((j & 0x0000ffff0000ffffULL) << 16);
        j = (j >> (64 - m));

        if (j > i)
            std::swap(a[i], a[(size_t)j]);
    }
}

static inline void fft_inplace(std::vector<std::complex<double>>& a)
{
    const std::size_t N = a.size();
    const unsigned int m = static_cast<unsigned int>(std::log2(N));
    const double PI = acosl(-1.0);

    // Pre‑compute twiddle factors for each stage
    std::vector<std::vector<std::complex<double>>> twiddles(m);
    for (unsigned int stage = 0; stage < m; ++stage)
    {
        const std::size_t half = 1ULL << stage;
        const std::size_t full  = half << 1;
        twiddles[stage].resize(half);
        const double theta = -PI / half;
        for (std::size_t k = 0; k < half; ++k)
            twiddles[stage][k] = std::complex<double>(std::cos(k * theta), std::sin(k * theta));
    }

    // Butterfly loops (decimation‑in‑time)
    for (unsigned int stage = 0; stage < m; ++stage)
    {
        const std::size_t half = 1ULL << stage;
        const std::size_t full  = half << 1;
        const auto& w = twiddles[stage];

        #pragma omp parallel for schedule(static)
        for (std::size_t block = 0; block < N; block += full)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                const std::size_t idx0 = block + j;
                const std::size_t idx1 = block + j + half;
                std::complex<double> t = a[idx1] * w[j];
                a[idx1] = a[idx0] - t;
                a[idx0] = a[idx0] + t;
            }
        }
    }

    // Bit‑reverse
    bit_reverse_inplace(a);
}

void fft(std::vector<std::complex<double>> const& x,
         std::vector<double>& r,
         std::vector<double>& i)
{
    std::vector<std::complex<double>> a = x;     // work copy
    fft_inplace(a);                              // fast transform

    // Split real/imaginary part
    const std::size_t N = a.size();
    r.resize(N);
    i.resize(N);

    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j)
    {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
