#include <algorithm>
#include <omp.h>

static constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/* Convolve the edge kernel with a grayscale image.
   The function signature must remain unchanged.
   This implementation:
   - uses OpenMP for parallelism (8 threads),
   - employs pointer arithmetic for locality,
   - unrolls the 3×3 kernel for a few micro‑optimisations,
   - keeps the original semantics (zero‑padding, clipping to [0,255]).
*/
void convolveKernel(std::vector<int> const& imageIn,
                    std::vector<int> &imageOut,
                    size_t N)
{
    const int n = static_cast<int>(N);
    const int* in  = imageIn.data();
    int* out = imageOut.data();

    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < n; ++i) {
        const int rowBase = i * n;
        for (int j = 0; j < n; ++j) {
            int sum = 0;

            // 3×3 neighbourhood
            // offset -1
            int x = i - 1;
            if (x >= 0) {
                // left
                if (j - 1 >= 0) sum += in[(x*n)+(j-1)] * edgeKernel[0][0];
                // center
                sum += in[(x*n)+j] * edgeKernel[0][1];
                // right
                if (j + 1 < n) sum += in[(x*n)+(j+1)] * edgeKernel[0][2];
            }
            // offset 0
            x = i;
            if (j - 1 >= 0) sum += in[(x*n)+(j-1)] * edgeKernel[1][0];
            sum += in[(x*n)+j] * edgeKernel[1][1];
            if (j + 1 < n) sum += in[(x*n)+(j+1)] * edgeKernel[1][2];
            // offset +1
            x = i + 1;
            if (x < n) {
                // left
                if (j - 1 >= 0) sum += in[(x*n)+(j-1)] * edgeKernel[2][0];
                // center
                sum += in[(x*n)+j] * edgeKernel[2][1];
                // right
                if (j + 1 < n) sum += in[(x*n)+(j+1)] * edgeKernel[2][2];
            }

            // clip to [0,255]
            if (sum < 0)       out[rowBase + j] = 0;
            else if (sum > 255)out[rowBase + j] = 255;
            else               out[rowBase + j] = sum;
        }
    }
}
