#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Solve the linear system Ax = b for x.
 * A is an NxN matrix stored in row‑major order, b and x are vectors of size N.
 *
 * The implementation follows the exact algorithm of the original function
 * (no pivoting, pivot zero leads to an early exit) but adds OpenMP
 * parallelism inside the inner elimination loop for speed on modern
 * x86‑64 CPUs with 8 hardware threads.
 *
 * Parameters
 * ----------
 * A : matrix (row‑major)   (input, not modified)
 * b : right‑hand side vector (input, not modified)
 * x : solution vector (output)
 * N : size of the system
 */
inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              size_t N)
{
    // Allocate working copies in contiguous memory
    std::vector<double> A_copy(A);   // copy of A
    std::vector<double> b_copy(b);   // copy of b

    // Forward elimination
    for (size_t i = 0; i + 1 < N; ++i)
    {
        const double pivot = A_copy[i * N + i];
        if (pivot == 0.0)            // exact zero: numerical instability → abort
            return;

        // Each row j > i can be updated independently.
        #pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j)
        {
            const double factor = A_copy[j * N + i] / pivot;
            // Update the remaining columns of row j
            double *row_j = &A_copy[j * N];
            const double *row_i = &A_copy[i * N];
            for (size_t k = i; k < N; ++k)
                row_j[k] -= factor * row_i[k];

            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution (serial is fine, cost is O(N²) but N is small)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        const double *row_i = &A_copy[i * N];
        for (size_t j = i + 1; j < N; ++j)
            sum += row_i[j] * x[j];
        x[i] = (b_copy[i] - sum) / A_copy[i * N + i];
    }
}
