// Optimised version of fftConjugate (C++17, gcc -O2 -fopenmp)
// The public interface is unchanged – the function still takes a
// reference to a std::vector<std::complex<double>> and works in‑place.
//
// The implementation follows a classic radix‑2 Cooley‑Tukey FFT:
//   • Butterfly stage – performed iteratively with pre‑computed twiddle
//     factors.  The complex arithmetic is explicit to avoid a
//     library call for every operation.
//   • Bit‑reversal permutation – uses a fast 32‑bit mask algorithm and
//     is parallelised with OpenMP.
//   • The final conjugation step – also parallelised.
//
// All math uses the standard C++ trig functions – the constant π is
// pre‑computed at compile time (constexpr) so the compiler can apply
// optimisations.
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

namespace detail {

// Helper to compute integer log2 for power‑of‑two sizes
constexpr inline unsigned int ilog2(unsigned int n)
{
    unsigned int r = 0;
    while (n >>= 1) ++r;
    return r;
}

// Fast bit‑reversal for 32‑bit words (N ≤ 4 294 967 296)
// The input word is truncated to the lower m bits.
inline uint32_t bit_reverse32(uint32_t x, unsigned int m)
{
    // 16‑bit swap
    x = ((x & 0x55555555U) << 1)  | ((x & 0xaaaaaaaaU) >> 1);
    x = ((x & 0x33333333U) << 2)  | ((x & 0xccccccccU) >> 2);
    x = ((x & 0x0f0f0f0fU) << 4)  | ((x & 0xf0f0f0f0U) >> 4);
    x = ((x & 0x00ff00ffU) << 8)  | ((x & 0xff00ff00U) >> 8);
    x = (x << 16) | (x >> 16);
    return x >> (32 - m);
}

} // namespace detail

// ---------------------------------------------------------------------------
// Public function – in‑place radix‑2 FFT followed by conjugation
// ---------------------------------------------------------------------------

void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;                      // nothing to do

    // -------------------------------------------------------------
    //                   butterfly (forward FFT)
    // -------------------------------------------------------------
    const double pi   = 3.14159265358979323846264338327950288L;
    const unsigned int stages = detail::ilog2(static_cast<unsigned int>(N));

    // Pre‑compute base rotation (exp(-j*2π/N)) for each stage
    std::complex<double> w_m = std::exp(std::complex<double>(0.0, -2.0 * pi / N));

    for (unsigned int stage = 0; stage < stages; ++stage) {
        const unsigned int step = 1U << stage;                // size of sub‑array
        const unsigned int half = step >> 1;                  // half‑size
        std::complex<double> w = 1.0L;                        // twiddle factor
        for (unsigned int j = 0; j < half; ++j, w *= w_m) {
            for (std::size_t i = j; i < N; i += step) {
                std::size_t k = i + half;
                std::complex<double> t = x[i] - x[k];
                x[i] += x[k];
                x[k] = t * w;
            }
        }
        // Advance base twiddle for next stage
        w_m = std::pow(w_m, 2);
    }

    // -------------------------------------------------------------
    //                bit‑reversal permutation
    // -------------------------------------------------------------
    const unsigned int m = detail::ilog2(static_cast<unsigned int>(N));

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t j = detail::bit_reverse32(static_cast<uint32_t>(i), m);
        if (j > i) std::swap(x[i], x[j]);
    }

    // -------------------------------------------------------------
    //                conjugate the result
    // -------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
