#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Ordinary Gaussian elimination but works on the sparse matrix directly.
   All numerical operations are performed on dense slices only where needed.
   The implementation keeps the original behaviour (partial pivoting,
   full elimination and back‑substitution), but avoids building the whole NxN
   matrix in memory and eliminates unnecessary memory copies.   */
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // --------------------------------------------------------------------
    // 1. Convert COO to CSR: one vector per row (list of (col,val))
    //    This keeps the sparsity while giving random access for elimination.
    // --------------------------------------------------------------------
    std::vector<std::vector<std::pair<size_t,double>>> rows(N);
    rows.reserve(N);
    for (auto const& e : A)
        rows[e.row].emplace_back(e.column, e.value);

    // --------------------------------------------------------------------
    // 2. Work arrays
    // --------------------------------------------------------------------
    std::vector<double> bcopy = b;     // copy of RHS (modified in place)
    std::vector<double> tempRow(N, 0.0); // scratch for row operations

    // --------------------------------------------------------------------
    // 3. Gaussian elimination with partial pivoting
    // --------------------------------------------------------------------
    for (size_t i = 0; i < N; ++i) {
        // --- pivot selection (partial pivoting, row i to N-1) ---
        size_t pivotRow = i;
        double maxVal = std::abs(rows[i][0].second == i ? rows[i][0].second : 0.0);
        for (size_t r = i+1; r < N; ++r) {
            auto it = std::find_if(rows[r].begin(), rows[r].end(),
                                   [i](auto const& p){ return p.first==i; });
            if (it != rows[r].end()) {
                double val = std::abs(it->second);
                if (val > maxVal) {
                    maxVal = val;
                    pivotRow = r;
                }
            }
        }

        // --- swap pivot row with current row (both data and RHS) ---
        if (pivotRow != i) {
            std::swap(rows[pivotRow], rows[i]);
            std::swap(bcopy[pivotRow], bcopy[i]);
        }

        // --- ensure we have a non‑zero pivot (assume solvable) ---
        double pivotVal = 0.0;
        for (auto const& p : rows[i])
            if (p.first == i) { pivotVal = p.second; break; }
        if (pivotVal == 0.0) continue;                // singular – skip

        // --- elimination of rows below i ---
        for (size_t k = i+1; k < N; ++k) {
            // find coefficient matrix[k][i]
            double coeff = 0.0;
            for (auto const& p : rows[k])
                if (p.first == i) { coeff = p.second; break; }
            if (coeff == 0.0) continue;              // already zero

            double factor = coeff / pivotVal;

            // row k = row k – factor * row i
            std::vector<std::pair<size_t,double>> newRow;
            newRow.reserve(rows[i].size() + rows[k].size());
            size_t ip = 0, kp = 0;
            while (ip < rows[i].size() && kp < rows[k].size()) {
                if (rows[i][ip].first < rows[k][kp].first) {
                    newRow.emplace_back(rows[i][ip].first,
                                        -factor * rows[i][ip].second);
                    ++ip;
                } else if (rows[i][ip].first > rows[k][kp].first) {
                    newRow.emplace_back(rows[k][kp].first,
                                        rows[k][kp].second);
                    ++kp;
                } else {
                    double val = rows[k][kp].second - factor * rows[i][ip].second;
                    if (std::abs(val) > 1e-12) 
                        newRow.emplace_back(rows[i][ip].first, val);
                    ++ip; ++kp;
                }
            }
            while (ip < rows[i].size()) {
                newRow.emplace_back(rows[i][ip].first,
                                    -factor * rows[i][ip].second);
                ++ip;
            }
            while (kp < rows[k].size()) {
                newRow.emplace_back(rows[k][kp].first,
                                    rows[k][kp].second);
                ++kp;
            }
            rows[k].swap(newRow);
            bcopy[k] -= factor * bcopy[i];
        }
    }

    // --------------------------------------------------------------------
    // 4. Back substitution
    // --------------------------------------------------------------------
    x.assign(N, 0.0);
    for (int i = static_cast<int>(N)-1; i >= 0; --i) {
        double sum = 0.0;
        for (auto const& p : rows[i]) {
            if (p.first > static_cast<size_t>(i))
                sum += p.second * x[p.first];
        }
        // find diagonal element
        double diag = 0.0;
        for (auto const& p : rows[i])
            if (p.first == static_cast<size_t>(i)) { diag = p.second; break; }
        x[i] = (bcopy[i] - sum) / diag;
    }
}
