#pragma once
#include <vector>
#include <omp.h>

/* Compute one iteration of a 5-point 2D jacobi stencil on `input`. Store the results in `output`.
   Each element of `input` will be averaged with its four neighbors and stored in the corresponding element of `output`.
   i.e. output[i,j] = (input[i,j-1] + input[i,j+1] + input[i-1,j] + input[i+1,j] + input[i,j]) / 5
   Boundaries are padded with zero (i.e. values outside the grid are treated as 0).
   `input` and `output` are NxN grids stored in row‑major order.
*/
inline void jacobi2D(std::vector<double> const& input, std::vector<double>& output, size_t N)
{
    if (N == 0) return;

    const size_t stride = N;
    const double denom = 5.0;

    /* ------------------------------------------------------------------
       Interior points: all four neighbors are inside the grid.
       ------------------------------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 1; i + 1 < N; ++i) {
        const double* rowm = &input[(i - 1) * stride];
        const double* row  = &input[i       * stride];
        const double* rowp = &input[(i + 1) * stride];
        double* outRow = &output[i * stride];

        for (size_t j = 1; j + 1 < N; ++j) {
            outRow[j] = (rowm[j] + rowp[j] + row[j - 1] + row[j + 1] + row[j]) * (1.0 / denom);
        }
    }

    /* ------------------------------------------------------------------
       First and last rows (i = 0 and i = N-1)
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        // Top row
        double sum = input[j];                                  // center
        if (j > 0)     sum += input[j - 1];                      // left
        if (j + 1 < N) sum += input[j + 1];                      // right
        if (N > 1)     sum += input[N + j];                     // below
        output[j] = sum * (1.0 / denom);

        // Bottom row
        const size_t idx = (N - 1) * stride + j;
        sum = input[idx];                                        // center
        if (j > 0)     sum += input[idx - 1];                     // left
        if (j + 1 < N) sum += input[idx + 1];                     // right
        if (N > 1)     sum += input[idx - stride];                // above
        output[idx] = sum * (1.0 / denom);
    }

    /* ------------------------------------------------------------------
       First and last columns of the intermediate rows (i = 1..N-2)
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i + 1 < N; ++i) {
        // Left column
        const size_t idxL = i * stride;
        double sum = input[idxL];                                 // center
        if (i > 0)     sum += input[(i - 1) * stride];             // above
        if (i + 1 < N) sum += input[(i + 1) * stride];             // below
        if (stride > 1) sum += input[idxL + 1];                    // right
        output[idxL] = sum * (1.0 / denom);

        // Right column
        const size_t idxR = i * stride + (N - 1);
        sum = input[idxR];                                        // center
        if (i > 0)     sum += input[(i - 1) * stride + (N - 1)];    // above
        if (i + 1 < N) sum += input[(i + 1) * stride + (N - 1)];    // below
        if (stride > 1) sum += input[idxR - 1];                    // left
        output[idxR] = sum * (1.0 / denom);
    }
}
